import{_ as s,o as e,c as n,ag as t}from"./chunks/framework.BDReElpY.js";const b=JSON.parse('{"title":"Bit Namespace","description":"","frontmatter":{},"headers":[],"relativePath":"guide/bit.md","filePath":"guide/bit.md"}'),p={name:"guide/bit.md"};function i(l,a,o,c,r,d){return e(),n("div",null,[...a[0]||(a[0]=[t(`<h1 id="bit-namespace" tabindex="-1">Bit Namespace <a class="header-anchor" href="#bit-namespace" aria-label="Permalink to &quot;Bit Namespace&quot;">​</a></h1><p>The <code>Bit</code> namespace provides hardware-accelerated parallel bit manipulation operations. These are essential for high-performance compression, encoding, and data structure implementations.</p><blockquote><p><strong>No import needed.</strong> <code>Bit.*</code> is a builtin namespace available everywhere.</p></blockquote><h2 id="quick-example" tabindex="-1">Quick Example <a class="header-anchor" href="#quick-example" aria-label="Permalink to &quot;Quick Example&quot;">​</a></h2><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// Extract specific bits from a value using a mask</span></span>
<span class="line"><span>let data: u64 = 0b1010_1100;</span></span>
<span class="line"><span>let mask: u64 = 0b1111_0000;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>let extracted = Bit.pext(data, mask);  // 0b1010 (bits at mask positions, packed)</span></span>
<span class="line"><span>let deposited = Bit.pdep(0b1010, mask); // 0b1010_0000 (bits deposited at mask positions)</span></span></code></pre></div><h2 id="parallel-bit-deposit" tabindex="-1">Parallel Bit Deposit <a class="header-anchor" href="#parallel-bit-deposit" aria-label="Permalink to &quot;Parallel Bit Deposit&quot;">​</a></h2><p>Scatter bits from source to positions indicated by the mask.</p><table tabindex="0"><thead><tr><th>Function</th><th>Signature</th><th>Description</th></tr></thead><tbody><tr><td><code>Bit.pdep(source, mask)</code></td><td><code>(u64, u64) → u64</code></td><td>Deposit bits at mask positions</td></tr></tbody></table><h3 id="how-pdep-works" tabindex="-1">How PDEP Works <a class="header-anchor" href="#how-pdep-works" aria-label="Permalink to &quot;How PDEP Works&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>source  = 0b_1011          (4 bits to deposit)</span></span>
<span class="line"><span>mask    = 0b_1010_0110     (positions to deposit into)</span></span>
<span class="line"><span>                   ↓↓  ↓↓</span></span>
<span class="line"><span>result  = 0b_1000_0110     (bits scattered to mask positions)</span></span></code></pre></div><p>Each bit from <code>source</code> is placed at the next set bit position in <code>mask</code>, left to right.</p><h3 id="platform-mapping" tabindex="-1">Platform Mapping <a class="header-anchor" href="#platform-mapping" aria-label="Permalink to &quot;Platform Mapping&quot;">​</a></h3><table tabindex="0"><thead><tr><th>x86</th><th>ARM</th></tr></thead><tbody><tr><td><code>PDEP</code> (BMI2, 1 cycle Intel / 3 cycles AMD Zen3+)</td><td>Software fallback (Apple Silicon has no SVE)</td></tr></tbody></table><h2 id="parallel-bit-extract" tabindex="-1">Parallel Bit Extract <a class="header-anchor" href="#parallel-bit-extract" aria-label="Permalink to &quot;Parallel Bit Extract&quot;">​</a></h2><p>Gather bits from source at positions indicated by the mask, packed contiguously.</p><table tabindex="0"><thead><tr><th>Function</th><th>Signature</th><th>Description</th></tr></thead><tbody><tr><td><code>Bit.pext(source, mask)</code></td><td><code>(u64, u64) → u64</code></td><td>Extract bits from mask positions</td></tr></tbody></table><h3 id="how-pext-works" tabindex="-1">How PEXT Works <a class="header-anchor" href="#how-pext-works" aria-label="Permalink to &quot;How PEXT Works&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>source  = 0b_1010_0110</span></span>
<span class="line"><span>mask    = 0b_1010_0110     (positions to extract from)</span></span>
<span class="line"><span>                   ↓↓  ↓↓</span></span>
<span class="line"><span>result  = 0b_1011          (extracted bits, packed together)</span></span></code></pre></div><p>Each bit at a set position in <code>mask</code> is extracted and packed into the result, starting from bit 0.</p><h3 id="platform-mapping-1" tabindex="-1">Platform Mapping <a class="header-anchor" href="#platform-mapping-1" aria-label="Permalink to &quot;Platform Mapping&quot;">​</a></h3><table tabindex="0"><thead><tr><th>x86</th><th>ARM</th></tr></thead><tbody><tr><td><code>PEXT</code> (BMI2, 1 cycle Intel / 3 cycles AMD Zen3+)</td><td>Software fallback</td></tr></tbody></table><h2 id="use-cases" tabindex="-1">Use Cases <a class="header-anchor" href="#use-cases" aria-label="Permalink to &quot;Use Cases&quot;">​</a></h2><h3 id="compression-huffman-decoding" tabindex="-1">Compression (Huffman Decoding) <a class="header-anchor" href="#compression-huffman-decoding" aria-label="Permalink to &quot;Compression (Huffman Decoding)&quot;">​</a></h3><p>PEXT/PDEP are the secret weapon behind modern compression:</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// Fast Huffman decode: extract variable-length code from bitstream</span></span>
<span class="line"><span>fn decodeSymbol(bitstream: u64, codeLen: u64): u64 {</span></span>
<span class="line"><span>    let mask = (1 as u64 &lt;&lt; codeLen) - 1;</span></span>
<span class="line"><span>    return Bit.pext(bitstream, mask);</span></span>
<span class="line"><span>}</span></span></code></pre></div><h3 id="bitmap-indexing" tabindex="-1">Bitmap Indexing <a class="header-anchor" href="#bitmap-indexing" aria-label="Permalink to &quot;Bitmap Indexing&quot;">​</a></h3><p>Fast rank/select on bitmaps (used in succinct data structures):</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// Count set bits before position (rank query)</span></span>
<span class="line"><span>fn rank(bitmap: u64, pos: u64): u64 {</span></span>
<span class="line"><span>    let mask = (1 as u64 &lt;&lt; pos) - 1;</span></span>
<span class="line"><span>    return Math.popcount(bitmap &amp; mask) as u64;</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// Select the nth set bit position</span></span>
<span class="line"><span>fn select(bitmap: u64, n: u64): u64 {</span></span>
<span class="line"><span>    let! b = bitmap;</span></span>
<span class="line"><span>    let! count: u64 = 0;</span></span>
<span class="line"><span>    while count &lt; n {</span></span>
<span class="line"><span>        b = b &amp; (b - 1);  // Clear lowest set bit</span></span>
<span class="line"><span>        count = count + 1;</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>    return Math.ctz(b) as u64;</span></span>
<span class="line"><span>}</span></span></code></pre></div><h3 id="chess-engines-bitboard-move-generation" tabindex="-1">Chess Engines (Bitboard Move Generation) <a class="header-anchor" href="#chess-engines-bitboard-move-generation" aria-label="Permalink to &quot;Chess Engines (Bitboard Move Generation)&quot;">​</a></h3><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// Extract all set bit positions from a bitboard</span></span>
<span class="line"><span>fn extractMoves(bitboard: u64): Vec&lt;u64&gt; {</span></span>
<span class="line"><span>    let! moves = Vec.new&lt;u64&gt;();</span></span>
<span class="line"><span>    let! bb = bitboard;</span></span>
<span class="line"><span>    while bb != 0 {</span></span>
<span class="line"><span>        let sq = Math.ctz(bb) as u64;  // Index of lowest set bit</span></span>
<span class="line"><span>        moves.push(sq);</span></span>
<span class="line"><span>        bb = bb &amp; (bb - 1);            // Clear that bit</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>    return moves;</span></span>
<span class="line"><span>}</span></span></code></pre></div><h3 id="data-packing" tabindex="-1">Data Packing <a class="header-anchor" href="#data-packing" aria-label="Permalink to &quot;Data Packing&quot;">​</a></h3><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// Pack 4 fields into a u64 using PDEP</span></span>
<span class="line"><span>fn packFields(a: u64, b: u64, c: u64, d: u64): u64 {</span></span>
<span class="line"><span>    let! result: u64 = 0;</span></span>
<span class="line"><span>    result = result | Bit.pdep(a, 0xFF);              // bits 0-7</span></span>
<span class="line"><span>    result = result | Bit.pdep(b, 0xFF00);             // bits 8-15</span></span>
<span class="line"><span>    result = result | Bit.pdep(c, 0xFF0000);           // bits 16-23</span></span>
<span class="line"><span>    result = result | Bit.pdep(d, 0xFF000000);         // bits 24-31</span></span>
<span class="line"><span>    return result;</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// Unpack with PEXT</span></span>
<span class="line"><span>fn unpackA(packed: u64): u64 {</span></span>
<span class="line"><span>    return Bit.pext(packed, 0xFF);</span></span>
<span class="line"><span>}</span></span></code></pre></div><h2 id="hardware-support" tabindex="-1">Hardware Support <a class="header-anchor" href="#hardware-support" aria-label="Permalink to &quot;Hardware Support&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Function</th><th>x86</th><th>ARM</th><th>Apple Silicon</th></tr></thead><tbody><tr><td><code>pdep</code></td><td>BMI2 (Haswell+ 2013)</td><td>Software fallback</td><td>Software fallback</td></tr><tr><td><code>pext</code></td><td>BMI2 (Haswell+ 2013)</td><td>Software fallback</td><td>Software fallback</td></tr></tbody></table><blockquote><p><strong>Note:</strong> On ARM/Apple Silicon, <code>pdep</code> and <code>pext</code> use efficient software fallback loops. On x86 with BMI2 support, they compile to single instructions.</p></blockquote><blockquote><p><strong>AMD Zen 1/2 warning:</strong> AMD Zen 1 and Zen 2 implement PDEP/PEXT with microcode (~18 cycles). True single-cycle support starts from AMD Zen 3+.</p></blockquote><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="/docs/guide/math#bit-operations">Math.popcount</a> — Count set bits</li><li><a href="/docs/guide/math#bit-operations">Math.clz / Math.ctz</a> — Leading/trailing zeros</li><li><a href="/docs/guide/math#bit-operations">Math.bswap</a> — Byte-swap (endian conversion)</li><li><a href="/docs/guide/crypto">Crypto Namespace</a> — Cryptographic operations</li><li><a href="/docs/guide/simd">SIMD</a> — Array-level bit operations</li></ul>`,38)])])}const u=s(p,[["render",i]]);export{b as __pageData,u as default};
